import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjTable } from "./OjTable";
export { OjTable };

/**
 * Create an instance of [[OjTable]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojTable(driver, By.id('my-oj-table'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojTable(driver: DriverLike, by: By): Promise<OjTable> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjTable
  if (!(webEl instanceof OjTable)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-table>`);
  }
  return webEl;
}

register("oj-table", OjTable);
